      const delta = new Delta().insert('Hello\nWorld!\n');
      delta.eachLine(spy);
      expect(spy.calls.count()).toEqual(2);
      expect(spy.calls.argsFor(0)).toEqual([
        new Delta().insert('Hello'),
        {},
        0,
      ]);
      expect(spy.calls.argsFor(1)).toEqual([
        new Delta().insert('World!'),
        {},
        1,
      ]);
    });

    it('non-document', () => {
